import React from 'react';
import { Link } from 'react-router-dom';

const diningCategories = [
  {
    title: 'Breakfast Favorites',
    description: 'Fresh morning plates prepared for light starts and hearty hotel breakfasts.',
    items: [
      {
        name: 'Classic English Breakfast',
        price: 'KSh 1,250',
        image: 'https://images.unsplash.com/photo-1544025162-d76694265947?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Pancake Stack With Syrup',
        price: 'KSh 950',
        image: 'https://images.unsplash.com/photo-1528207776546-365bb710ee93?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Omelette & Toast Combo',
        price: 'KSh 780',
        image: 'https://images.unsplash.com/photo-1510693206972-df098062cb71?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Tropical Fruit Bowl',
        price: 'KSh 640',
        image: 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'French Toast Delight',
        price: 'KSh 890',
        image: 'https://images.unsplash.com/photo-1484723091739-30a097e8f929?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Breakfast Sausage Platter',
        price: 'KSh 1,050',
        image: 'https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&w=900&q=80',
      },
    ],
  },
  {
    title: 'Main Courses',
    description: 'Chef-crafted dishes with rich flavors for lunch and dinner service.',
    items: [
      {
        name: 'Grilled Beef Steak',
        price: 'KSh 2,450',
        image: 'https://images.unsplash.com/photo-1544025162-d76694265947?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Herb Chicken Supreme',
        price: 'KSh 1,980',
        image: 'https://images.unsplash.com/photo-1600891964092-4316c288032e?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Creamy Seafood Pasta',
        price: 'KSh 2,200',
        image: 'https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Vegetable Stir Fry Rice Bowl',
        price: 'KSh 1,350',
        image: 'https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Roasted Lamb With Herbs',
        price: 'KSh 2,650',
        image: 'https://images.unsplash.com/photo-1544025162-d76694265947?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Signature Salmon Plate',
        price: 'KSh 2,480',
        image: 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=900&q=80',
      },
    ],
  },
  {
    title: 'Snacks & Fast Bites',
    description: 'Quick favorites for casual dining, room service, and light meals.',
    items: [
      {
        name: 'Double Cheese Burger',
        price: 'KSh 1,150',
        image: 'https://images.unsplash.com/photo-1568901346375-23c9450c58cd?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Crispy Chicken Wrap',
        price: 'KSh 980',
        image: 'https://images.unsplash.com/photo-1608039755401-742074f0548d?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Loaded Fries Basket',
        price: 'KSh 720',
        image: 'https://images.unsplash.com/photo-1573080496219-bb080dd4f877?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Club Sandwich Deluxe',
        price: 'KSh 890',
        image: 'https://images.unsplash.com/photo-1528735602780-2552fd46c7af?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Spicy Chicken Wings',
        price: 'KSh 1,020',
        image: 'https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Mini Pizza Bites',
        price: 'KSh 1,180',
        image: 'https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=900&q=80',
      },
    ],
  },
  {
    title: 'Desserts & Drinks',
    description: 'Sweet finishes and refreshing beverages to complete your dining experience.',
    items: [
      {
        name: 'Chocolate Lava Cake',
        price: 'KSh 780',
        image: 'https://images.unsplash.com/photo-1606313564200-e75d5e30476c?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Vanilla Berry Cheesecake',
        price: 'KSh 860',
        image: 'https://images.unsplash.com/photo-1533134242443-d4fd215305ad?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Fresh Passion Juice',
        price: 'KSh 420',
        image: 'https://images.unsplash.com/photo-1622597467836-f3285f2131b8?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Signature Cappuccino',
        price: 'KSh 390',
        image: 'https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Ice Cream Sundae',
        price: 'KSh 690',
        image: 'https://images.unsplash.com/photo-1563805042-7684c019e1cb?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Fresh Strawberry Mocktail',
        price: 'KSh 560',
        image: 'https://images.unsplash.com/photo-1513558161293-cdaf765ed2fd?auto=format&fit=crop&w=900&q=80',
      },
    ],
  },
];

const featuredPlates = [
  {
    title: 'Chef Signature Seafood Platter',
    price: 'KSh 3,450',
    image: 'https://images.unsplash.com/photo-1559847844-5315695dadae?auto=format&fit=crop&w=1200&q=80',
    tag: 'Chef Special',
    description:
      'A premium selection of grilled fish, prawns, and seasonal sides prepared for guests who want a rich seafood experience.',
  },
  {
    title: 'Garden Brunch Board',
    price: 'KSh 2,100',
    image: 'https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&w=1200&q=80',
    tag: 'Weekend Favorite',
    description:
      'A colorful brunch spread with eggs, fruit, pastries, and fresh juice, ideal for slow mornings and shared dining.',
  },
  {
    title: 'Royal Grill Experience',
    price: 'KSh 3,980',
    image: 'https://images.unsplash.com/photo-1544025162-d76694265947?auto=format&fit=crop&w=1200&q=80',
    tag: 'Premium Dining',
    description:
      'An elevated grill plate with steak, roast vegetables, and signature sauces served in a bold restaurant presentation.',
  },
  {
    title: 'Dessert Tasting Trio',
    price: 'KSh 1,420',
    image: 'https://images.unsplash.com/photo-1563805042-7684c019e1cb?auto=format&fit=crop&w=1200&q=80',
    tag: 'Sweet Selection',
    description:
      'Three dessert favorites plated together for guests who want to explore more than one sweet finish in a single order.',
  },
];

const Dining = () => {
  return (
    <section className="dining-page">
      <div className="dining-page__hero">
        <p className="dining-page__eyebrow">Dining Experience</p>
        <h2>Explore delicious dishes across our most loved food categories.</h2>
        <p className="dining-page__intro">
          Enjoy breakfast classics, premium main dishes, quick bites, desserts, and refreshing
          drinks prepared with care by our kitchen team.
        </p>
      </div>

      <section className="dining-showcase">
        <div className="dining-showcase__intro">
          <p className="dining-page__eyebrow">Featured Plates</p>
          <h3>More dishes in a richer chef-style layout.</h3>
          <p>
            These featured selections highlight premium presentation, bigger portions, and a more
            elevated restaurant experience.
          </p>
        </div>

        <div className="dining-showcase__grid">
          {featuredPlates.map((plate, index) => (
            <article
              className={`dining-showcase-card ${index % 2 === 1 ? 'dining-showcase-card--reverse' : ''}`}
              key={plate.title}
            >
              <img className="dining-showcase-card__image" src={plate.image} alt={plate.title} />

              <div className="dining-showcase-card__content">
                <p className="dining-showcase-card__tag">{plate.tag}</p>
                <h4>{plate.title}</h4>
                <p>{plate.description}</p>
                <div className="dining-showcase-card__footer">
                  <strong>{plate.price}</strong>
                  <Link className="dining-order-button" to="/makepayment">
                    Order Now
                  </Link>
                </div>
              </div>
            </article>
          ))}
        </div>
      </section>

      <div className="dining-categories">
        {diningCategories.map((category) => (
          <article className="dining-category-card" key={category.title}>
            <div className="dining-category-card__header">
              <h3>{category.title}</h3>
              <p>{category.description}</p>
            </div>

            <div className="dining-menu-list">
              {category.items.map((item) => (
                <div className="dining-menu-item" key={item.name}>
                  <img className="dining-menu-item__image" src={item.image} alt={item.name} />

                  <div className="dining-menu-item__content">
                    <h4>{item.name}</h4>
                    <span>{category.title}</span>
                  </div>

                  <div className="dining-menu-item__actions">
                    <strong>{item.price}</strong>
                    <Link className="dining-order-button" to="/makepayment">
                      Order Now
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          </article>
        ))}
      </div>
    </section>
  );
};

export default Dining;
